import React, { useEffect, useRef, useMemo } from 'react';
import { useAppContext } from './context/AppContext';
import Timer from './components/common/Timer';
import QuestionnaireTimer from './components/questionnaire/QuestionnaireTimer';
import PageRouter from './components/PageRouter';
import StepNavigation from './components/common/StepNavigation';
import QuestionnaireNavigation from './components/questionnaire/QuestionnaireNavigation';
import ApiConfigDebug from './components/debug/ApiConfigDebug';
// import DevToolsPanel from './components/dev/DevToolsPanel';  // 文件不存在，暂时注释
import { isQuestionnairePage, getQuestionnaireStepNumber, TOTAL_QUESTIONNAIRE_STEPS } from './utils/pageMappings';
// import { initGlobalErrorHandling } from './utils/errorHandler'; // 可选：启用错误过滤
import './styles/global.css'; // Ensure global styles are imported

// 导入模块路由器
const ModuleRouter = React.lazy(() => import('./modules/ModuleRouter.jsx'));

/**
 * 主应用内容组件
 * 根据登录状态和任务状态渲染不同内容
 */
const AppContent = () => {
  const {
    isLoggedIn,
    isAuthenticated,
    currentPageId,
    isTimeUp,
    isTaskFinished,
    setCurrentPageId,
    setIsTaskFinished,
    startTaskTimer,
    currentStepNumber,
    totalUserSteps,
    submitPageData,
    questionnaireRemainingTime,
    isQuestionnaireTimeUp,
    isQuestionnaireStarted,
    questionnaireStartTime,
    startQuestionnaireTimer,
    saveQuestionnaireAnswer,
    getQuestionnaireAnswer,
    completeQuestionnaire,
    taskStartTime,
    currentUser,
    batchCode,
    examNo,
    // 模块系统需要的状态
    remainingTime,
    pageNum,
    currentPageData,
    pageEnterTime,
    authToken,
    moduleUrl,
    questionnaireData,
    questionnaireAnswers,
    isQuestionnaireCompleted,
    logOperation,
    collectAnswer,
    // 提交相关能力（提供给模块）
    submitPageDataWithInfo,
    // 暴露给模块路由器的登出与清理
    handleLogout,
    clearAllCache
  } = useAppContext();

  // 用于防止重复日志输出
  const moduleLoggedRef = useRef(false);

  // 🚀 性能优化：提前声明 useMemo，避免 Hook 顺序问题
  // 必须在所有条件语句之前调用，符合 React Hooks 规则
  const globalContext = useMemo(() => {
    // 如果不使用模块系统，返回 null
    if (!moduleUrl || !isAuthenticated) {
      return null;
    }

    return {
      currentPageId,
      remainingTime,
      taskStartTime,
      batchCode,
      examNo,
      pageNum,
      currentPageData,
      pageEnterTime,
      isLoggedIn,
      isAuthenticated,
      authToken,
      currentUser,
      moduleUrl,
      isTaskFinished,
      isTimeUp,
      // 问卷相关状态和函数
      questionnaireData,
      questionnaireAnswers,
      isQuestionnaireCompleted,
      questionnaireRemainingTime,
      isQuestionnaireTimeUp,
      isQuestionnaireStarted,
      questionnaireStartTime,
      startQuestionnaireTimer,
      saveQuestionnaireAnswer,
      getQuestionnaireAnswer,
      completeQuestionnaire,
      logOperation,
      collectAnswer,
      // 数据提交（模块调用）
      submitPageData,
      submitPageDataWithInfo,
      // 暴露登出与清理能力给模块
      handleLogout,
      clearAllCache
    };
  }, [
    // 只依赖真正重要的状态变化
    moduleUrl,
    isAuthenticated,
    currentPageId,
    // remainingTime 故意省略 - 计时器更新不应触发模块重新渲染
    taskStartTime,
    batchCode,
    examNo,
    pageNum,
    currentPageData,
    pageEnterTime,
    isLoggedIn,
    authToken,
    currentUser,
    isTaskFinished,
    isTimeUp,
    questionnaireData,
    questionnaireAnswers,
    isQuestionnaireCompleted,
    questionnaireRemainingTime,
    isQuestionnaireTimeUp,
    isQuestionnaireStarted,
    questionnaireStartTime,
    // 函数引用通常是稳定的，但为了安全起见也包含
    startQuestionnaireTimer,
    saveQuestionnaireAnswer,
    getQuestionnaireAnswer,
    completeQuestionnaire,
    logOperation,
    collectAnswer,
    submitPageData,
    submitPageDataWithInfo,
    handleLogout,
    clearAllCache
  ]);

  // 🚀 性能优化：使用useMemo缓存authInfo
  const authInfo = useMemo(() => {
    if (!moduleUrl || !isAuthenticated) {
      return null;
    }
    return {
      url: moduleUrl,
      pageNum: pageNum,
      examNo: examNo,
      batchCode: batchCode
    };
  }, [moduleUrl, pageNum, examNo, batchCode, isAuthenticated]);

  useEffect(() => {
    if (isTimeUp && !isTaskFinished && currentPageId !== 'Page_18_Solution_Selection') {
      console.log("时间到，自动提交当前页面并标记完成...");
      
      // 使用AppContext的submitPageData，它已包含session过期处理
      const doTimeUpSubmission = async () => {
        await submitPageData();
        // 无论提交成功与否，都标记完成并回落到最后一页
        setIsTaskFinished(true);
        setCurrentPageId('Page_18_Solution_Selection');
      };
      
      doTimeUpSubmission();
    }
  }, [isTimeUp, isTaskFinished, currentPageId, submitPageData, setCurrentPageId, setIsTaskFinished]);

  // 计时器检查：确保在任务页面时计时器已启动
  useEffect(() => {
    if (isAuthenticated && isLoggedIn && !taskStartTime && !isTaskFinished) {
      // 定义需要计时器的页面
      const taskPages = [
        'Page_02_Introduction',
        'Page_03_Dialogue_Question',
        'Page_04_Material_Reading_Factor_Selection',
        'Page_10_Hypothesis_Focus',
        'Page_11_Solution_Design_Measurement_Ideas',
        'Page_12_Solution_Evaluation_Measurement_Critique',
        'Page_13_Transition_To_Simulation',
        'Page_14_Simulation_Intro_Exploration',
        'Page_15_Simulation_Question_1',
        'Page_16_Simulation_Question_2',
        'Page_17_Simulation_Question_3',
        'Page_18_Solution_Selection'
      ];
      
      if (taskPages.includes(currentPageId)) {
        console.log(`[App] 🚨 检测到用户在任务页面 ${currentPageId} 但计时器未启动，立即启动计时器`);
        startTaskTimer();
      }
    }
  }, [isAuthenticated, isLoggedIn, taskStartTime, isTaskFinished, currentPageId, startTaskTimer]);

  if (!isAuthenticated) {
    return (
      <div className="app-container">
        {/* 全屏提示现在使用DOM管理器处理，不再使用React组件 */}
        <div className="task-wrapper">
          <PageRouter />
        </div>
      </div>
    );
  }

  // 检查当前页面是否是问卷页面（P20-P28）
  const isQuestionnairePageId = (pageId) => {
    return pageId && pageId.startsWith('Page_2') && ['Page_20_Questionnaire_Intro', 'Page_21_Curiosity_Questions', 'Page_22_Creativity_Questions', 'Page_23_Imagination_Questions', 'Page_24_Science_Efficacy_Questions', 'Page_25_Environment_Questions', 'Page_26_School_Activities', 'Page_27_Outschool_Activities', 'Page_28_Effort_Submit'].includes(pageId);
  };

  if (isTaskFinished && currentPageId !== 'Page_18_Solution_Selection' && !isQuestionnairePageId(currentPageId)) {
    // 如果任务已标记为完成，但当前页面不是最终页且不是问卷页面，则强制回落到最终页
    setCurrentPageId('Page_18_Solution_Selection');
  }

  // 任务进行中，显示计时器和页面路由器（注意事项页面开始显示计时器）
  const showTimer = currentPageId !== 'Page_01_Precautions'; // 注意事项页面不显示计时器
  const showStepNavigation = currentStepNumber > 0;
  
  // 判断是否是问卷页面
  const isCurrentPageQuestionnaire = isQuestionnairePage(currentPageId);
  const currentQuestionnaireStep = getQuestionnaireStepNumber(currentPageId);


  // 如果有模块URL，使用模块路由器
  // 但必须确保用户已认证（双重检查，防止localStorage残留导致的问题）
  if (moduleUrl && isAuthenticated) {
    // 只在第一次或moduleUrl变化时输出日志
    if (process.env.NODE_ENV === 'development' && !moduleLoggedRef.current) {
      console.log('[App] 📦 渲染模块系统界面');
      moduleLoggedRef.current = true;
    }
    return (
      <div className="app-container">
        {/* 全屏提示现在使用DOM管理器处理，不再使用React组件 */}

        {/* UserInfoBar 已移到 AppShell 全局渲染 */}
        {showTimer && (isCurrentPageQuestionnaire ? <QuestionnaireTimer /> : <Timer />)}
        <div className="main-content-wrapper">
          {/* 模块系统下不显示全局导航，模块内部有自己的导航系统 */}
          <div className="task-wrapper">
            <React.Suspense fallback={
              <div style={{
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'center',
                minHeight: '200px',
                fontSize: '16px'
              }}>
                🚀 正在加载模块系统...
              </div>
            }>
              <ModuleRouter
                globalContext={globalContext}
                authInfo={authInfo}
              />
            </React.Suspense>
          </div>
        </div>
      </div>
    );
  }

  // 重置日志标志（当不使用模块系统时）
  if (moduleLoggedRef.current) {
    moduleLoggedRef.current = false;
  }

  // 默认情况：使用传统页面路由器
  return (
    <div className="app-container">
      {/* 全屏提示现在使用DOM管理器处理，不再使用React组件 */}

      {/* UserInfoBar 已移到 AppShell 全局渲染 */}
      {/* 根据当前页面类型显示不同的计时器 */}
      {showTimer && (isCurrentPageQuestionnaire ? <QuestionnaireTimer /> : <Timer />)}
      <div className="main-content-wrapper">
        {/* 根据当前页面类型显示不同的导航 */}
        {isCurrentPageQuestionnaire ? (
          <QuestionnaireNavigation
            currentQuestionnaireStep={currentQuestionnaireStep}
            totalQuestionnaireSteps={TOTAL_QUESTIONNAIRE_STEPS}
          />
        ) : (
          showStepNavigation && <StepNavigation currentStepNumber={currentStepNumber} totalSteps={totalUserSteps} />
        )}
        <div className="task-wrapper">
          <PageRouter />
        </div>
      </div>
    </div>
  );
};

/**
 * 应用主组件
 * 包含全局状态管理和页面路由
 */
function App() {
  // 显示调试信息（可以通过查询参数控制）
  const showDebug = new URLSearchParams(window.location.search).get('debug') === 'true';
  
  return (
    <>
      <AppContent />
      {showDebug && <ApiConfigDebug />}
      {/* DevToolsPanel disabled: component is not available */}
    </>
  );
}

export default App;

/**
 * @file App.test.jsx
 * @description 测试主应用组件的模块系统激活功能
 * @author James (Developer)
 * @created 2025-07-26
 */

import { render, screen, waitFor } from '@testing-library/react';
import { vi } from 'vitest';
import App from './App';

// Mock 模块路由器
vi.mock('./modules/ModuleRouter.jsx', () => ({
  default: vi.fn().mockImplementation(({ globalContext, authInfo }) => (
    <div data-testid="module-router">
      <div data-testid="module-url">{authInfo?.url}</div>
      <div data-testid="exam-no">{authInfo?.examNo}</div>
      Mock ModuleRouter
    </div>
  ))
}));

// Mock AppContext
vi.mock('./context/AppContext', () => ({
  AppProvider: ({ children }) => <div data-testid="app-provider">{children}</div>,
  useAppContext: vi.fn()
}));

// Mock 其他组件
vi.mock('./components/common/Timer', () => ({
  default: () => <div data-testid="timer">Timer</div>
}));

vi.mock('./components/common/UserInfoBar', () => ({
  default: () => <div data-testid="user-info-bar">UserInfoBar</div>
}));

vi.mock('./components/PageRouter', () => ({
  default: () => <div data-testid="page-router">PageRouter</div>
}));

vi.mock('./components/common/StepNavigation', () => ({
  default: () => <div data-testid="step-navigation">StepNavigation</div>
}));

vi.mock('./components/questionnaire/QuestionnaireTimer', () => ({
  default: () => <div data-testid="questionnaire-timer">QuestionnaireTimer</div>
}));

vi.mock('./components/questionnaire/QuestionnaireNavigation', () => ({
  default: () => <div data-testid="questionnaire-navigation">QuestionnaireNavigation</div>
}));

vi.mock('./components/debug/ApiConfigDebug', () => ({
  default: () => <div data-testid="api-config-debug">ApiConfigDebug</div>
}));

vi.mock('./utils/pageMappings', () => ({
  isQuestionnairePage: vi.fn().mockReturnValue(false),
  getQuestionnaireStepNumber: vi.fn().mockReturnValue(1),
  TOTAL_QUESTIONNAIRE_STEPS: 9
}));

const { useAppContext } = vi.mocked(await import('./context/AppContext'));

describe('App Component - Module System Activation', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  test('应该在用户未认证时渲染PageRouter', () => {
    // Mock 未认证状态
    useAppContext.mockReturnValue({
      isAuthenticated: false,
      isLoggedIn: false,
      currentPageId: 'Page_01_Login',
      // 其他必需的状态
      moduleUrl: '',
      currentStepNumber: 0,
      totalUserSteps: 0,
      isTaskFinished: false,
      questionnaireRemainingTime: 0,
      isQuestionnaireTimeUp: false,
      setCurrentPageId: vi.fn(),
      setIsTaskFinished: vi.fn(),
      startTaskTimer: vi.fn(),
      submitPageData: vi.fn(),
      logOperation: vi.fn(),
      collectAnswer: vi.fn()
    });

    render(<App />);

    // 验证登录页面渲染
    expect(screen.getByTestId('page-router')).toBeInTheDocument();
    expect(screen.queryByTestId('module-router')).not.toBeInTheDocument();
    expect(screen.queryByTestId('user-info-bar')).not.toBeInTheDocument();
  });

  test('应该在用户认证后且有moduleUrl时渲染ModuleRouter', async () => {
    // Mock 认证状态 + 模块URL
    useAppContext.mockReturnValue({
      isAuthenticated: true,
      isLoggedIn: true,
      currentPageId: 'Page_02_Introduction',
      moduleUrl: '/seven-grade', // 关键：提供模块URL
      currentStepNumber: 1,
      totalUserSteps: 10,
      isTaskFinished: false,
      questionnaireRemainingTime: 600000,
      isQuestionnaireTimeUp: false,
      currentUser: {
        studentName: '测试学生',
        schoolName: '测试学校',
        schoolCode: 'TEST001'
      },
      examNo: 'EXAM123',
      batchCode: 'BATCH456',
      remainingTime: 2400000,
      taskStartTime: new Date(),
      setCurrentPageId: vi.fn(),
      setIsTaskFinished: vi.fn(),
      startTaskTimer: vi.fn(),
      submitPageData: vi.fn(),
      logOperation: vi.fn(),
      collectAnswer: vi.fn()
    });

    render(<App />);

    // 验证 ModuleRouter 被渲染
    await waitFor(() => {
      expect(screen.getByTestId('module-router')).toBeInTheDocument();
    });

    // 验证正确的 authInfo 被传递
    expect(screen.getByTestId('module-url')).toHaveTextContent('/seven-grade');
    expect(screen.getByTestId('exam-no')).toHaveTextContent('EXAM123');

    // 验证必要的 UI 组件仍然渲染
    expect(screen.getByTestId('user-info-bar')).toBeInTheDocument();
    expect(screen.getByTestId('timer')).toBeInTheDocument();
  });

  test('应该在用户认证后但没有moduleUrl时渲染传统PageRouter', () => {
    // Mock 认证状态但无模块URL
    useAppContext.mockReturnValue({
      isAuthenticated: true,
      isLoggedIn: true,
      currentPageId: 'Page_02_Introduction',
      moduleUrl: '', // 关键：没有模块URL
      currentStepNumber: 1,
      totalUserSteps: 10,
      isTaskFinished: false,
      questionnaireRemainingTime: 600000,
      isQuestionnaireTimeUp: false,
      currentUser: {
        studentName: '测试学生'
      },
      examNo: 'EXAM123',
      batchCode: 'BATCH456',
      setCurrentPageId: vi.fn(),
      setIsTaskFinished: vi.fn(),
      startTaskTimer: vi.fn(),
      submitPageData: vi.fn(),
      logOperation: vi.fn(),
      collectAnswer: vi.fn()
    });

    render(<App />);

    // 验证传统 PageRouter 被渲染
    expect(screen.getByTestId('page-router')).toBeInTheDocument();
    expect(screen.queryByTestId('module-router')).not.toBeInTheDocument();

    // 验证必要的 UI 组件仍然渲染
    expect(screen.getByTestId('user-info-bar')).toBeInTheDocument();
    expect(screen.getByTestId('timer')).toBeInTheDocument();
  });

  test('应该正确传递globalContext给ModuleRouter', async () => {
    const mockContext = {
      isAuthenticated: true,
      isLoggedIn: true,
      currentPageId: 'Page_15_Test',
      moduleUrl: '/seven-grade',
      currentStepNumber: 5,
      totalUserSteps: 10,
      isTaskFinished: false,
      remainingTime: 1800000,
      taskStartTime: new Date('2024-07-26T10:00:00'),
      currentUser: { studentName: '张三' },
      examNo: 'E123',
      batchCode: 'B456',
      questionnaireRemainingTime: 600000,
      isQuestionnaireTimeUp: false,
      questionnaireData: {},
      questionnaireAnswers: {},
      isQuestionnaireCompleted: false,
      setCurrentPageId: vi.fn(),
      setIsTaskFinished: vi.fn(),
      startTaskTimer: vi.fn(),
      submitPageData: vi.fn(),
      logOperation: vi.fn(),
      collectAnswer: vi.fn()
    };

    useAppContext.mockReturnValue(mockContext);

    // 重新 mock ModuleRouter 以验证传入的 props
    const MockModuleRouter = vi.fn().mockImplementation(({ globalContext, authInfo }) => (
      <div data-testid="module-router">
        <div data-testid="global-context-present">{globalContext ? 'present' : 'missing'}</div>
        <div data-testid="auth-info-present">{authInfo ? 'present' : 'missing'}</div>
      </div>
    ));

    vi.doMock('./modules/ModuleRouter.jsx', () => ({
      default: MockModuleRouter
    }));

    render(<App />);

    await waitFor(() => {
      expect(screen.getByTestId('module-router')).toBeInTheDocument();
    });

    // 验证 ModuleRouter 被正确调用
    expect(MockModuleRouter).toHaveBeenCalledWith(
      expect.objectContaining({
        globalContext: expect.objectContaining({
          currentPageId: 'Page_15_Test',
          moduleUrl: '/seven-grade',
          examNo: 'E123',
          batchCode: 'B456',
          isAuthenticated: true,
          logOperation: expect.any(Function),
          collectAnswer: expect.any(Function)
        }),
        authInfo: expect.objectContaining({
          url: '/seven-grade',
          pageNum: 'Page_15_Test',
          examNo: 'E123',
          batchCode: 'B456'
        })
      }),
      expect.any(Object)
    );
  });

  test('应该在问卷页面正确渲染QuestionnaireTimer', async () => {
    const { isQuestionnairePage } = vi.mocked(await import('./utils/pageMappings'));
    isQuestionnairePage.mockReturnValue(true);

    useAppContext.mockReturnValue({
      isAuthenticated: true,
      isLoggedIn: true,
      currentPageId: 'Page_21_Curiosity_Questions',
      moduleUrl: '/seven-grade',
      currentStepNumber: 1,
      totalUserSteps: 10,
      isTaskFinished: false,
      questionnaireRemainingTime: 300000,
      isQuestionnaireTimeUp: false,
      setCurrentPageId: vi.fn(),
      setIsTaskFinished: vi.fn(),
      startTaskTimer: vi.fn(),
      submitPageData: vi.fn(),
      logOperation: vi.fn(),
      collectAnswer: vi.fn()
    });

    render(<App />);

    // 验证问卷计时器被渲染
    expect(screen.getByTestId('questionnaire-timer')).toBeInTheDocument();
    expect(screen.queryByTestId('timer')).not.toBeInTheDocument();
  });
});

import React, { useEffect, useState } from 'react';
import ReactDOM from 'react-dom';
import '../styles/FullscreenPrompt.css';
import {
  onFullscreenPreferenceChange,
  shouldEnforceFullscreen
} from '../utils/fullscreenPreference';

/**
 * 全屏提示组件
 * 当用户退出全屏时显示，提示用户重新进入全屏
 * 使用 React Portal 渲染到 document.body，确保在所有内容之上
 */
const FullscreenPrompt = ({ onEnterFullscreen }) => {
  const [fullscreenCheckEnabled, setFullscreenCheckEnabled] = useState(() => {
    const shouldEnforce = shouldEnforceFullscreen();
    console.log('[FullscreenPrompt] 初始化全屏检查:', shouldEnforce);
    return shouldEnforce;
  });

  useEffect(() => {
    const unsubscribe = onFullscreenPreferenceChange((enabled) => {
      console.log('[FullscreenPrompt] 全屏偏好变化:', enabled);
      setFullscreenCheckEnabled(Boolean(enabled));
    });

    return unsubscribe;
  }, []);

  console.log('[FullscreenPrompt] 渲染检查:', { fullscreenCheckEnabled });

  if (!fullscreenCheckEnabled) {
    console.log('[FullscreenPrompt] 不显示：全屏检查未启用');
    return null;
  }

  console.log('[FullscreenPrompt] 显示退出全屏提示');

  // 创建一个容器元素来确认Portal是否工作
  useEffect(() => {
    console.log('[FullscreenPrompt] 组件已挂载，准备显示Portal');
    // 在body中添加一个标记来确认
    const marker = document.createElement('div');
    marker.id = 'fullscreen-prompt-marker';
    marker.style.cssText = 'position: fixed; top: 0; left: 0; background: yellow; color: black; padding: 5px; z-index: 2147483647;';
    marker.textContent = 'FullscreenPrompt组件已渲染';
    document.body.appendChild(marker);

    return () => {
      // 清理标记
      const existingMarker = document.getElementById('fullscreen-prompt-marker');
      if (existingMarker) {
        existingMarker.remove();
      }
    };
  }, []);

  // 使用 React Portal 将内容渲染到 document.body
  // 这样可以绕过所有中间容器，确保显示在最顶层
  const content = (
    <div className="fullscreen-prompt-overlay" style={{
        // 内联样式以确保样式生效
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundColor: 'rgba(0, 0, 0, 0.85)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 2147483646, // 接近最大值
        pointerEvents: 'auto'
      }}>
        <div className="fullscreen-prompt-container">
          <div className="fullscreen-prompt-icon">
            <svg
              width="64"
              height="64"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3" />
            </svg>
          </div>

          <h2 className="fullscreen-prompt-title">请进入全屏模式</h2>

          <p className="fullscreen-prompt-message">
            为了确保测试环境的完整性和避免意外操作，
            <br />
            请点击下方按钮重新进入全屏模式。
          </p>

          <button
            className="fullscreen-prompt-button"
            onClick={onEnterFullscreen}
            autoFocus
          >
            进入全屏
          </button>

          <p className="fullscreen-prompt-hint">
