 * 使用数据记录与提交服务上下文的自定义Hook
 * @returns {Object} 数据记录与提交服务上下文值
 */
export const useDataLogger = () => {
  const context = useContext(DataLoggerContext);
  if (context === undefined) {
    throw new Error('useDataLogger必须在DataLoggerProvider内部使用');
  }
  return context;
};

