import React, { createContext, useCallback, useContext, useEffect, useMemo, useRef } from 'react';
import PropTypes from 'prop-types';
import { useAppContext } from '@/context/AppContext';

// Internal noop logger (Phase 0 keeps noise low)
const debugLog = () => {};

// React context for Flow
const FlowRuntimeContext = createContext(null);

/**
 * Feature flag helpers
 */
function parseFlag(val, def) {
  if (val === undefined || val === null) return !!def;
  const s = String(val).toLowerCase();
  return s === '1' || s === 'true' || s === 'yes' || s === 'on';
}

/**
 * FlowProvider (Phase 0 skeleton)
 * - Creates Flow runtime context without changing existing behavior
 * - When disabled via flag, renders children as-is (no provider)
 */
export function FlowProvider({
  flowId = '',
  submoduleId = '',
  stepIndex = 0,
  progress = null,
  orchestratorRef = null,
  heartbeatEnabled = false,
  children,
}) {
  const isEnabled = parseFlag(import.meta?.env?.VITE_FLOW_PROVIDER_ENABLED, false);

  // Do not wrap with provider when disabled to avoid any behavioral shifts
  if (!isEnabled) {
    return children;
  }

  // AppContext integration (Phase 0: read-only + refs)
  const app = useAppContext();

  // Cache selected fields in refs to avoid re-creating context value
  const examNoRef = useRef(app?.examNo ?? '');
  const batchCodeRef = useRef(app?.batchCode ?? '');
  const remainingTimeRef = useRef(Number(app?.remainingTime ?? 0));
  const questionnaireRemainingTimeRef = useRef(Number(app?.questionnaireRemainingTime ?? 0));
  const currentPageIdRef = useRef(app?.currentPageId ?? '');

  useEffect(() => { examNoRef.current = app?.examNo ?? ''; }, [app?.examNo]);
  useEffect(() => { batchCodeRef.current = app?.batchCode ?? ''; }, [app?.batchCode]);
  useEffect(() => { remainingTimeRef.current = Number(app?.remainingTime ?? 0); }, [app?.remainingTime]);
  useEffect(() => {
    questionnaireRemainingTimeRef.current = Number(app?.questionnaireRemainingTime ?? 0);
  }, [app?.questionnaireRemainingTime]);
  useEffect(() => { currentPageIdRef.current = app?.currentPageId ?? ''; }, [app?.currentPageId]);

  // Stable accessors to imperative helpers
  const submitPageRef = useRef(app?.submitPageData);
  useEffect(() => { submitPageRef.current = app?.submitPageData; }, [app?.submitPageData]);

  // Forward the orchestrator ref through a stable holder
  const orchestratorRefRef = useRef(orchestratorRef || null);
  useEffect(() => { orchestratorRefRef.current = orchestratorRef || null; }, [orchestratorRef]);

  // Stable wrappers
  const navigateToNextStep = useCallback(() => {
    const ref = orchestratorRefRef.current;
    const inst = ref && 'current' in ref ? ref.current : null;
    if (!inst) return false;
    if (typeof inst.nextStep === 'function') return inst.nextStep();
    if (typeof inst.next === 'function') return inst.next();
    return false;
  }, []);

  const submitPage = useCallback(async (options = {}) => {
    const fn = submitPageRef.current;
    if (typeof fn === 'function') {
      try {
        return await fn(options);
      } catch (e) {
        debugLog('[FlowProvider] submitPage error (delegated):', e);
        return false;
      }
    }
    debugLog('[FlowProvider] submitPage ignored (no app.submitPageData)');
    return false;
  }, []);

  const getUserContext = useCallback(() => ({
    examNo: examNoRef.current || '',
    batchCode: batchCodeRef.current || '',
    currentPageId: currentPageIdRef.current || '',
  }), []);

  const getTimerSnapshot = useCallback(() => ({
    remainingTime: Number(remainingTimeRef.current || 0),
    questionnaireRemainingTime: Number(questionnaireRemainingTimeRef.current || 0),
  }), []);

  const getFlowContext = useCallback(() => ({
    flowId: flowId ?? '',
    submoduleId: submoduleId ?? '',
    stepIndex: typeof stepIndex === 'number' ? stepIndex : 0,
    modulePageNum: progress?.modulePageNum ?? null,
  }), [flowId, submoduleId, stepIndex, progress?.modulePageNum]);

  // Context value memo - only depends on minimal keys
  const value = useMemo(() => {
    return {
      flowId: flowId ?? '',
      submoduleId: submoduleId ?? '',
      stepIndex: typeof stepIndex === 'number' ? stepIndex : 0,
      progress: { modulePageNum: progress?.modulePageNum ?? null },

      orchestratorRef: orchestratorRefRef,
      navigateToNextStep,
      submitPage,

      heartbeat: { enabled: !!heartbeatEnabled },

      getUserContext,
      getTimerSnapshot,
      getFlowContext,
    };
    // Intentionally NOT depending on AppContext values; selectors and wrappers use refs
  }, [flowId, submoduleId, stepIndex, progress?.modulePageNum, heartbeatEnabled]);

  return (
    <FlowRuntimeContext.Provider value={value}>{children}</FlowRuntimeContext.Provider>
  );
}

FlowProvider.propTypes = {
  flowId: PropTypes.string,
  submoduleId: PropTypes.string,
  stepIndex: PropTypes.number,
  progress: PropTypes.shape({
    modulePageNum: PropTypes.oneOfType([PropTypes.string, PropTypes.oneOf([null])]),
  }),
  orchestratorRef: PropTypes.shape({ current: PropTypes.any }),
  heartbeatEnabled: PropTypes.bool,
  children: PropTypes.node.isRequired,
};

/**
 * 获取 FlowContext（严格：未找到时抛错）
 */
export function useFlowContext() {
  const ctx = useContext(FlowRuntimeContext);
  if (!ctx) {
    throw new Error('[FlowProvider] FlowContext is not available. Ensure provider is enabled and mounted.');
  }
  return ctx;
}

/**
 * 获取 FlowContext（宽松：未找到时返回 null）
 */
export function useOptionalFlowContext() {
  return useContext(FlowRuntimeContext);
}

export default FlowProvider;

import { useCallback, useRef } from 'react';
import { useAppContext } from '../context/AppContext';
import EventTypes from '@shared/services/submission/eventTypes.js';

const toInputString = (value) => {
  if (value === null || value === undefined) return '';
  return String(value);
};

/**
 * 数据记录自定义Hook
 * 提供标准化的数据记录方法
 * 
 * @param {string} pageId - 当前页面ID（可选，用于特殊逻辑）
 * @returns {Object} 数据记录方法集合
 */
export const useDataLogging = (pageId = null) => {
  const { logOperation, collectAnswer } = useAppContext();
  const inputStateRef = useRef({});

  const getInputState = useCallback((target) => {
    if (!target) return { lastValue: '', hasFocused: false };
    if (!inputStateRef.current[target]) {
      inputStateRef.current[target] = { lastValue: '', hasFocused: false };
    }
    return inputStateRef.current[target];
  }, []);

  /**
   * 记录输入事件
   * @param {string} targetElement - 目标元素描述
   * @param {string} value - 输入值
   */
  const logInput = useCallback((targetElement, value) => {
    const state = getInputState(targetElement);
    const prevValue = state.lastValue ?? '';
    const nextValue = toInputString(value);

    if (!state.hasFocused) {
      logOperation({
        targetElement,
        eventType: EventTypes.INPUT_FOCUS,
        value: '聚焦输入框'
      });
      state.hasFocused = true;
    }

    if (nextValue.length < prevValue.length) {
      logOperation({
        targetElement,
        eventType: EventTypes.INPUT_DELETE,
        value: {
          action: 'delete',
          prevLength: prevValue.length,
          nextLength: nextValue.length
        }
      });
    }

    logOperation({
      targetElement,
      eventType: EventTypes.INPUT_CHANGE,
      value: {
        prev: prevValue,
        next: nextValue
      }
    });

    state.lastValue = nextValue;
  }, [getInputState, logOperation]);

  /**
   * 记录输入框失焦事件并收集答案
   * @param {string} targetElement - 目标元素描述
   * @param {string} value - 输入值
   * @param {string} answerElement - 答案元素描述（可选，默认使用targetElement）
   */
  const logInputBlur = useCallback((targetElement, value, answerElement = null) => {
    const state = getInputState(targetElement);
    const normalizedValue = toInputString(value);

    logOperation({
      targetElement,
      eventType: EventTypes.INPUT_BLUR,
      value: normalizedValue
    });
    state.lastValue = normalizedValue;
    state.hasFocused = false;

    collectAnswer({
      targetElement: answerElement || targetElement,
      value: normalizedValue
    });
  }, [collectAnswer, getInputState, logOperation]);

  /**
   * 记录按钮点击事件
   * @param {string} buttonName - 按钮名称
   * @param {string} action - 执行的动作描述
   */
  const logButtonClick = useCallback((buttonName, action = '点击') => {
    logOperation({
      targetElement: `${buttonName}按钮`,
      eventType: 'click',
      value: action
    });
  }, [logOperation]);

  /**
   * 记录复选框变更事件
   * @param {string} checkboxName - 复选框名称
   * @param {boolean} checked - 是否选中
   * @param {string} answerElement - 答案元素描述（可选）
   */
  const logCheckboxChange = useCallback((checkboxName, checked, answerElement = null) => {
    logOperation({
      targetElement: `${checkboxName}复选框`,
      eventType: checked ? 'checkbox_check' : 'checkbox_uncheck',
      value: checked ? '选中' : '取消选中'
    });
    
    if (answerElement) {
      collectAnswer({
        targetElement: answerElement,
        value: checked
      });
    }
  }, [logOperation, collectAnswer]);

  /**
   * 记录单选按钮选择事件
   * @param {string} radioName - 单选按钮组名称
   * @param {string} selectedValue - 选中的值
   * @param {string} answerElement - 答案元素描述（可选）
   */
  const logRadioSelect = useCallback((radioName, selectedValue, answerElement = null) => {
    logOperation({
      targetElement: `${radioName}单选按钮`,
      eventType: 'radio_select',
      value: selectedValue
    });
    
    if (answerElement) {
      collectAnswer({
        targetElement: answerElement,
        value: selectedValue
      });
    }
  }, [logOperation, collectAnswer]);

  /**
   * 记录模态框打开事件
   * @param {string} modalName - 模态框名称
   * @param {string} modalId - 模态框ID
   */
  const logModalOpen = useCallback((modalName, modalId) => {
    logOperation({
      targetElement: `${modalName}模态框`,
      eventType: 'modal_open',
      value: modalId
    });
  }, [logOperation]);

  /**
   * 记录模态框关闭事件
   * @param {string} modalName - 模态框名称
   * @param {string} modalId - 模态框ID
   * @param {number} viewDuration - 查看时长（秒）
   */
  const logModalClose = useCallback((modalName, modalId, viewDuration = 0) => {
    logOperation({
      targetElement: `${modalName}模态框`,
      eventType: 'modal_close',
      value: viewDuration > 0 ? `查看时长${viewDuration}秒` : `关闭${modalId}`
    });
  }, [logOperation]);

  /**
   * 记录页面进入事件
   * @param {string} pageName - 页面名称
   */
  const logPageEnter = useCallback((pageName) => {
    logOperation({
      targetElement: '页面',
      eventType: 'page_enter',
      value: pageName
    });
  }, [logOperation]);

  /**
   * 记录页面退出事件
   * @param {string} pageName - 页面名称
   */
  const logPageExit = useCallback((pageName) => {
    logOperation({
      targetElement: '页面',
      eventType: 'page_exit',
      value: pageName
    });
  }, [logOperation]);

  /**
   * 记录数据提交事件
   * @param {string} submitType - 提交类型
   * @param {boolean} success - 是否成功
   * @param {string} message - 附加信息
   */
  const logSubmit = useCallback((submitType, success, message = '') => {
    logOperation({
      targetElement: '数据提交',
      eventType: 'submit',
      value: `${submitType} - ${success ? '成功' : '失败'}${message ? ': ' + message : ''}`
    });
  }, [logOperation]);

  /**
   * 记录计时器事件
   * @param {string} timerName - 计时器名称
   * @param {string} action - 动作（start/stop）
   * @param {number} value - 计时值（可选）
   */
  const logTimer = useCallback((timerName, action, value = null) => {
    logOperation({
      targetElement: `${timerName}计时器`,
      eventType: action === 'start' ? 'timer_start' : 'timer_stop',
      value: value !== null ? `${value}秒` : action
    });
  }, [logOperation]);

  /**
   * 直接收集答案（不记录操作）
   * @param {string} targetElement - 目标元素描述
   * @param {any} value - 答案值
   */
  const collectDirectAnswer = useCallback((targetElement, value) => {
    collectAnswer({
      targetElement,
      value
    });
  }, [collectAnswer]);

  return {
    logInput,
    logInputBlur,
    logButtonClick,
    logCheckboxChange,
    logRadioSelect,
    logModalOpen,
    logModalClose,
    logPageEnter,
    logPageExit,
    logSubmit,
    logTimer,
    collectDirectAnswer,
    // 原始方法，用于特殊场景
    logOperation,
    collectAnswer
  };
};

/**
 * 模块系统错误边界组件
 * 捕获模块加载和运行时错误，提供降级机制
 */

import React from 'react';
import STORAGE_KEYS, { removeStorageItem } from '@shared/services/storage/storageKeys.js';

class ModuleErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null,
      retryCount: 0
    };
  }

  static getDerivedStateFromError(error) {
    // 更新 state 使下一次渲染能够显示降级后的 UI
    return { hasError: true };
  }

  componentDidCatch(error, errorInfo) {
    // 捕获错误信息
    console.error('[ModuleErrorBoundary] 捕获到模块错误:', error, errorInfo);
    
    this.setState({
      error: error,
      errorInfo: errorInfo
    });

    // 上报错误信息（可选）
    this.reportError(error, errorInfo);
  }

  /**
   * 上报错误信息到日志系统
   */
  reportError = (error, errorInfo) => {
    try {
      // 这里可以添加错误上报逻辑
      console.log('[ModuleErrorBoundary] 错误报告:', {
        error: error.toString(),
        stack: error.stack,
        componentStack: errorInfo.componentStack,
        timestamp: new Date().toISOString(),
        userAgent: navigator.userAgent,
        url: window.location.href
      });
    } catch (reportError) {
      console.error('[ModuleErrorBoundary] 错误上报失败:', reportError);
    }
  };

  /**
   * 重试加载模块
   */
  handleRetry = () => {
    console.log('[ModuleErrorBoundary] 用户请求重试模块加载');
    
    this.setState(prevState => ({
      hasError: false,
      error: null,
      errorInfo: null,
      retryCount: prevState.retryCount + 1
    }));
  };

  /**
   * 切换到传统模式
   */
  handleFallbackToTraditional = () => {
    console.log('[ModuleErrorBoundary] 用户选择切换到传统模式');
    
    try {
      // 清除模块系统标志
      localStorage.removeItem('useModuleSystem');
      removeStorageItem(STORAGE_KEYS.CORE_MODULE_URL);
      // 统一键名：优先清理 pageNum，兼容清理旧的 modulePageNum
      removeStorageItem(STORAGE_KEYS.CORE_PAGE_NUM);
      localStorage.removeItem('hci-pageNum');

      // 刷新页面以加载传统模式
      window.location.reload();
    } catch (error) {
      console.error('[ModuleErrorBoundary] 切换到传统模式失败:', error);
    }
  };

  render() {
    if (this.state.hasError) {
      const { error, errorInfo, retryCount } = this.state;
      const maxRetries = 3;
      
      return (
        <div style={{
          padding: '20px',
          margin: '20px',
          border: '2px solid #ff7875',
          borderRadius: '8px',
          backgroundColor: '#fff2f0',
          fontFamily: 'Arial, sans-serif'
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            marginBottom: '16px'
          }}>
            <span style={{ fontSize: '24px', marginRight: '8px' }}>⚠️</span>
            <h2 style={{ 
              margin: 0, 
              color: '#cf1322',
              fontSize: '18px'
            }}>
              模块系统遇到问题
            </h2>
          </div>

          <div style={{ marginBottom: '16px' }}>
            <p style={{ margin: '0 0 8px 0', color: '#666' }}>
              测评模块加载时出现错误，您可以选择以下操作：
            </p>
          </div>

          <div style={{ 
            display: 'flex', 
            gap: '12px', 
            marginBottom: '20px',
            flexWrap: 'wrap'
          }}>
            {retryCount < maxRetries && (
              <button
                onClick={this.handleRetry}
                style={{
                  padding: '8px 16px',
                  backgroundColor: '#1890ff',
                  color: 'white',
                  border: 'none',
                  borderRadius: '4px',
                  cursor: 'pointer',
                  fontSize: '14px'
                }}
              >
                🔄 重试加载 ({retryCount}/{maxRetries})
              </button>
            )}
            
            <button
              onClick={this.handleFallbackToTraditional}
              style={{
                padding: '8px 16px',
                backgroundColor: '#52c41a',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer',
                fontSize: '14px'
              }}
            >
              ✅ 使用传统模式
            </button>
          </div>

          {/* 开发环境显示详细错误信息 */}
          {import.meta.env.DEV && (
            <details style={{ 
              backgroundColor: '#f5f5f5', 
              padding: '12px', 
              borderRadius: '4px',
              fontSize: '12px'
            }}>
              <summary style={{ 
                cursor: 'pointer', 
                fontWeight: 'bold',
                marginBottom: '8px'
              }}>
                📋 详细错误信息 (开发模式)
              </summary>
              
              <div style={{ marginTop: '8px' }}>
                <strong>错误消息:</strong>
                <pre style={{ 
                  backgroundColor: '#fff', 
                  padding: '8px', 
                  border: '1px solid #d9d9d9',
