                <div style={{ marginTop: '8px' }}>
                  <strong>组件堆栈:</strong>
                  <pre style={{ 
                    backgroundColor: '#fff', 
                    padding: '8px', 
                    border: '1px solid #d9d9d9',
                    borderRadius: '4px',
                    overflow: 'auto',
