      editDuration: 0,
      characterCount: 0,
      isEmpty: true,
      isValid: false,
    },
    {
      questionNumber: 2,
      questionText: '2. 解释为什么含水量的变化会影响小球的下落时间。',
      answerText: '',
      startEditTime: null,
      lastEditTime: null,
      editDuration: 0,
      characterCount: 0,
      isEmpty: true,
      isValid: false,
    },
    {
      questionNumber: 3,
      questionText: '3. 如果实验中改变温度参数,你预测会对结果产生什么影响?',
      answerText: '',
      startEditTime: null,
