const Page11_Analysis1 = () => {
  const {
    session,
    logOperation,
    collectAnswer,
    clearOperations,
    buildMarkObject,
    navigateToPage,
    submitPageData,
  } = useTrackingContext();

  const [selectedAnswer, setSelectedAnswer] = useState(null);
  const [isNavigating, setIsNavigating] = useState(false);

  // 记录页面进入
  useEffect(() => {
    logOperation({
      action: 'page_enter',
      target: '页面',
      value: 'Page11_Analysis1',
      time: new Date().toISOString(),
    });

    return () => {
      logOperation({
        action: 'page_exit',
        target: '页面',
        value: 'Page11_Analysis1',
        time: new Date().toISOString(),
      });
    };
  }, [logOperation]);

  // 处理实验开始 - 计算所有量筒的下落时间
  const handleExperimentStart = useCallback(
    (waterContent, temperature) => {
      // 🔧 修改：使用 simulation_timing_started eventType 以匹配7年级蒸馒头模块
      logOperation({
        action: 'simulation_timing_started',
        target: '计时开始按钮_分析页1',
        value: `温度${temperature}°C`,
        time: new Date().toISOString(),
      });

      // 使用物理模型计算下落时间
      const fallTime = calculateFallTime(waterContent, temperature);
      return fallTime;
    },
    [logOperation]
  );

  // 处理实验完成
  const handleExperimentComplete = useCallback(
    experimentData => {
      // experimentData 是一个数组，包含所有量筒的数据
      // [{waterContent: 15, temperature: 30, fallTime: 16.5}, ...]

      // 🔧 修改：构建符合7年级蒸馒头模块格式的 simulation_run_result
      const temperature = experimentData[0]?.temperature || 25; // 获取当前实验的温度
      const runId = `Analysis1_${Date.now()}`;

      // 构建结果数组，格式与蒸馒头模块类似
      const resultsForLog = experimentData.map(item => ({
        WaterContent: item.waterContent, // 含水量
        FallTime: item.fallTime, // 下落时间
      }));

      logOperation({
        action: 'simulation_run_result',
        target: '模拟实验运行结果',
        value: {
          Run_ID: `run_Page_11_Analysis1_${runId}`,
          Set_Temperature: temperature, // 设定温度
          Results: resultsForLog,
        },
        time: new Date().toISOString(),
      });
    },
    [logOperation]
  );

  // 处理重置
  const handleReset = useCallback(() => {
    logOperation({
      action: '点击',
      target: '重置按钮_分析页',
      value: '重置实验',
      time: new Date().toISOString(),
    });
  }, [logOperation]);

  // 处理答案选择
  const handleAnswerChange = useCallback(
    answer => {
      setSelectedAnswer(answer);

      logOperation({
        action: '单选',
        target: '实验分析',
        value: answer,
        time: new Date().toISOString(),
      });
    },
    [logOperation]
  );

  // 处理下一页
  const handleNextPage = useCallback(async () => {
    if (!selectedAnswer || isNavigating) {
      return;
    }

    setIsNavigating(true);

    try {
      logOperation({
        action: '点击',
        target: '下一页按钮',
        value: '下一页',
        time: new Date().toISOString(),
      });

      // 同步构建答案列表，避免依赖异步的 collectAnswer 状态
      const answerList = [{ targetElement: 'analysis_q1', value: selectedAnswer }];

      // 构建并提交MarkObject
      // 从session获取当前页码而不是硬编码
      const pageInfo = PAGE_MAPPING[session.currentPage];
      // 传入同步构建的 answerList，确保提交时 answerList 不为空
      const markObject = buildMarkObject(
        String(session.currentPage),
        pageInfo?.desc || '实验分析1',
        { answerList }
      );
      const success = await submitPageData(markObject);

      if (success) {
        clearOperations();
        await navigateToPage(10);
      } else {
        throw new Error('数据提交失败');
      }
    } catch (error) {
      console.error('[Page11_Analysis1] 导航失败:', error);
      alert(error.message || '页面跳转失败，请重试');
      setIsNavigating(false);
    }
  }, [
    selectedAnswer,
    isNavigating,
    logOperation,
    collectAnswer,
    buildMarkObject,
    submitPageData,
    clearOperations,
    navigateToPage,
    session,
  ]);

  return (
    <PageLayout showNavigation={true} showTimer={true}>
      <div className={styles.container}>
        <header className={styles.header}>
          <div className={styles.badge}>9</div>
          <div className={styles.headerContent}>
            <div className={styles.pageTitle}>
              <h2>实验分析（1/3）</h2>
            </div>
          </div>
        </header>

        <div className={styles.contentLayout}>
          {/* 左侧:实验操作区 - 4个量筒同时下落 */}
          <div className={styles.leftPanel}>
            <IntegratedExperimentPanel
              waterContentOptions={WATER_CONTENT_OPTIONS}
              temperatureOptions={TEMPERATURE_OPTIONS}
              onExperimentStart={handleExperimentStart}
              onExperimentComplete={handleExperimentComplete}
              onReset={handleReset}
            />
          </div>

          {/* 右侧:问题区 */}
          <div className={styles.rightPanel}>
            <div className={styles.questionCard}>
              <div className={styles.questionHeader}>
                <span className={styles.questionNumber}>问题 1</span>
              </div>

              <div className={styles.questionBody}>
                <p className={styles.questionText}>
                  模拟实验表明,在<strong>40℃</strong>条件下,蜂蜜的含水量为多少时,小钢球的下落时间
                  <strong>最长</strong>?
                </p>

                <div className={styles.optionsGroup} role="radiogroup">
                  {WATER_CONTENT_OPTIONS.map(option => (
                    <label
                      key={option}
                      className={`${styles.optionLabel} ${
                        selectedAnswer === `${option}%` ? styles.selected : ''
                      }`}
                    >
                      <input
                        type="radio"
                        name="analysis_q1"
                        value={`${option}%`}
                        checked={selectedAnswer === `${option}%`}
                        onChange={() => handleAnswerChange(`${option}%`)}
                        className={styles.optionInput}
                      />
                      <span className={styles.optionText}>{option}%</span>
                    </label>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>

        <footer className={styles.navigationFooter}>
          <button
            type="button"
            className={styles.btnPrimary}
            onClick={handleNextPage}
            disabled={!selectedAnswer || isNavigating}
          >
            <span>{selectedAnswer ? (isNavigating ? '提交中...' : '下一页') : '请先回答问题'}</span>
            <svg
              width="16"
              height="16"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2.5"
            >
              <path d="M5 12h14M12 5l7 7-7 7" />
            </svg>
          </button>
        </footer>
      </div>
    </PageLayout>
  );
};

