import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import EventTypes from '@shared/services/submission/eventTypes.js';
import { usePageSubmissionContext } from '@shared/ui/PageFrame/AssessmentPageFrame.jsx';
import { formatTimestamp } from '@shared/services/dataLogger.js';
import experimentImg from '../assets/images/experiment.png';
import { useAppContext } from '../context/AppContext';
import TextInput from '../components/common/TextInput';
import NavigationButton from '../components/common/NavigationButton';

/**
 * 蒸馒头:方案设计 - 测量方法构思页面
 * 让用户输入三种不同的测量面团体积的方法构思
 */
const SolutionDesignPage = () => {
  const { 
    navigateToPage, 
    currentPageId,
    setPageEnterTime
  } = useAppContext();
  const { submitPage, logOperation } = usePageSubmissionContext();

  const [ideas, setIdeas] = useState({
    idea1: '',
    idea2: '',
    idea3: ''
  });
  const [showAlert, setShowAlert] = useState(false);
  const [alertMessage, setAlertMessage] = useState('');
  const operationsRef = useRef([]);
  const inputStatesRef = useRef({
    idea1: { focused: false, lastValue: '' },
    idea2: { focused: false, lastValue: '' },
    idea3: { focused: false, lastValue: '' },
  });
  const pageLoadedRef = useRef(false);

  const recordOperation = useCallback((operation) => {
    const normalizedOperation = {
      ...operation,
      time: formatTimestamp(new Date()),
    };
    logOperation(normalizedOperation);
    operationsRef.current = [...operationsRef.current, normalizedOperation];
  }, [logOperation]);

  // 页面进入记录
  useEffect(() => {
    if (pageLoadedRef.current) return;
    pageLoadedRef.current = true;
    operationsRef.current = [];
    inputStatesRef.current = {
      idea1: { focused: false, lastValue: '' },
      idea2: { focused: false, lastValue: '' },
      idea3: { focused: false, lastValue: '' },
    };
    setPageEnterTime(new Date());
  }, [setPageEnterTime]);

  const isNextEnabled = useMemo(
    () => Object.values(ideas).some(idea => idea.trim().length > 0),
    [ideas],
  );

  // 监听输入变化，更新状态并记录
  const handleIdeaChange = useCallback((key, value) => {
    const prevValue = inputStatesRef.current[key]?.lastValue || '';
    const nextValue = value;

    setIdeas(prev => ({
      ...prev,
      [key]: nextValue
    }));

    if (nextValue.length < prevValue.length) {
      recordOperation({
        eventType: EventTypes.INPUT_DELETE,
        targetElement: `输入框_${key}`,
        value: { action: 'delete', prevLength: prevValue.length, nextLength: nextValue.length }
      });
    }

    recordOperation({
      eventType: EventTypes.INPUT_CHANGE,
      targetElement: `输入框_${key}`,
      value: { prev: prevValue, next: nextValue }
    });

    inputStatesRef.current[key] = {
      ...(inputStatesRef.current[key] || { focused: false, lastValue: '' }),
      lastValue: nextValue
    };
  }, [recordOperation]);

  /**
   * 处理输入框失焦事件
   * @param {string} key - 想法键名
   * @param {string} value - 输入值
   */
  const handleInputBlur = useCallback((key, value) => {
    recordOperation({
      eventType: EventTypes.INPUT_BLUR,
      targetElement: `输入框_${key}`,
      value: value || ''
    });

    inputStatesRef.current[key] = {
      ...(inputStatesRef.current[key] || { focused: false, lastValue: '' }),
      focused: false,
      lastValue: value || ''
    };
  }, [recordOperation]);

  const handleInputFocus = useCallback((key) => {
    const currentState = inputStatesRef.current[key] || { focused: false, lastValue: '' };
    if (currentState.focused) return;

    recordOperation({
      eventType: EventTypes.INPUT_FOCUS,
      targetElement: `输入框_${key}`,
      value: '聚焦'
    });

    inputStatesRef.current[key] = {
      ...currentState,
      focused: true,
      lastValue: ideas[key] || ''
    };
  }, [ideas, recordOperation]);

  /**
   * 处理"下一页"按钮点击
   */
  const handleNextClick = useCallback(async () => {
    if (!isNextEnabled) {
      setAlertMessage('请至少输入一种测量方法构思。');
      setShowAlert(true);
      recordOperation({
        eventType: EventTypes.CLICK_BLOCKED,
        targetElement: 'next_button',
        value: { reason: '未输入想法', missing: ['measurement_ideas'] }
      });
      return false;
    }

    setShowAlert(false);
    recordOperation({
      eventType: EventTypes.CLICK,
      targetElement: 'next_button',
      value: '提交测量方法构思'
    });

    const answers = Object.entries(ideas).map(([key, value]) => {
      const trimmed = value.trim();
      if (!trimmed) return null;
      const index = parseInt(key.replace('idea', ''), 10);
      const targetElement = Number.isFinite(index) ? `测量想法_${index}` : `测量想法_${key}`;
      return { targetElement, value: trimmed };
    }).filter(Boolean);

    const submissionSuccess = await submitPage({
      answers,
      operations: operationsRef.current,
    });
    if (submissionSuccess) {
      navigateToPage('Page_12_Solution_Evaluation_Measurement_Critique', { skipSubmit: true });
      return true;
    }

    setAlertMessage('数据提交失败，请稍后再试。');
    setShowAlert(true);
    return false;
  }, [ideas, isNextEnabled, navigateToPage, recordOperation, submitPage]);

  return (
    <div className="page-content page-fade-in">
      {showAlert && (
        <div style={{ position: 'fixed', top: '20px', left: '50%', transform: 'translateX(-50%)', background: '#fdecea', color: '#a94442', padding: '10px 16px', borderRadius: '6px', border: '1px solid #f5c6cb', boxShadow: '0 2px 8px rgba(0,0,0,0.08)', zIndex: 1050 }}>
          {alertMessage}
        </div>
      )}
      <h1 className="page-title">蒸馒头:方案设计</h1>

      <div className="solution-design-container">
        <div className="experiment-image">
          {/* 实验场景图片 */}
          <img 
            src={experimentImg} 
            alt="科学实验场景"
            className="experiment-scene-image"
          />
        </div>
        
        <div className="instruction-section">
          <p className="instruction-text">
            小明想测量面团在不同条件下发酵前、后的体积变化，以探究温度和时间对面团发酵的影响。
            请帮助小明设计一些方法，用来测量面团的体积。
          </p>
          <p className="instruction-highlight">
            请在下方输入框中写下你的测量方法构思（至少提出一种想法）
          </p>
        </div>
        
        <div className="ideas-input-section">
          <div className="idea-input-container">
            <h3 className="section-subtitle">想法一:</h3>
            <TextInput
              value={ideas.idea1}
              onFocus={() => handleInputFocus('idea1')}
              onChange={(value) => handleIdeaChange('idea1', value)}
              onBlur={() => handleInputBlur('idea1', ideas.idea1)}
              placeholder="请描述你的测量方法构思..."
              isMultiline={true}
              elementDesc="测量方法构思输入框1"
              rows={3}
            />
          </div>
          
          <div className="idea-input-container">
            <h3 className="section-subtitle">想法二:</h3>
            <TextInput
              value={ideas.idea2}
              onFocus={() => handleInputFocus('idea2')}
              onChange={(value) => handleIdeaChange('idea2', value)}
              onBlur={() => handleInputBlur('idea2', ideas.idea2)}
              placeholder="请描述你的测量方法构思..."
              isMultiline={true}
              elementDesc="测量方法构思输入框2"
              rows={3}
            />
          </div>
          
          <div className="idea-input-container">
            <h3 className="section-subtitle">想法三:</h3>
            <TextInput
              value={ideas.idea3}
              onFocus={() => handleInputFocus('idea3')}
              onChange={(value) => handleIdeaChange('idea3', value)}
              onBlur={() => handleInputBlur('idea3', ideas.idea3)}
              placeholder="请描述你的测量方法构思..."
              isMultiline={true}
              elementDesc="测量方法构思输入框3"
              rows={3}
            />
          </div>
        </div>
      </div>
      
      {!isNextEnabled && (
        <p className="validation-tip">请至少输入一种测量方法构思</p>
      )}
      
      <div className="navigation-container">
        <NavigationButton 
          onClick={handleNextClick} 
          disabled={!isNextEnabled}
          className="primary-button"
        >
          下一页
        </NavigationButton>
      </div>
    </div>
  );
};

export default SolutionDesignPage;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { useAppContext } from '../../context/AppContext';
import { CURIOSITY_QUESTIONS, LIKERT_OPTIONS_4 } from '../../utils/questionnaireData';
import LikertScale from '../../components/questionnaire/LikertScale';
import { ensureScrollToTop } from '../../utils/pageTransitionUtils';
import styles from './QuestionnairePage.module.css';

const PAGE_ID = 'Page_21_Curiosity_Questions';

/**
 * P21: 好奇心问题组
 * @returns {JSX.Element}
 */
function Page_21_Curiosity_Questions() {
  const {
    navigateToPage,
    isQuestionnaireTimeUp,
    saveQuestionnaireAnswer,
    getQuestionnaireAnswer,
    setPageEnterTime,
    logOperation,
    collectAnswer,
    submitPageData,
  } = useAppContext();

  const [answers, setAnswers] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  // 页面加载时只执行一次的操作，使用ref确保不重复执行
  const pageLoadedRef = useRef(false);
  useEffect(() => {
    if (!pageLoadedRef.current) {
      pageLoadedRef.current = true;
      // 确保页面滚动到顶部
      ensureScrollToTop();
      setPageEnterTime(new Date());
      logOperation({
        eventType: 'page_load',
        targetElement: 'P21_CuriosityQuestionsPage',
      });
    }
  }, []);

  // 获取保存的答案，只在组件挂载时执行一次
  useEffect(() => {
    const savedAnswers = getQuestionnaireAnswer(PAGE_ID);
    if (savedAnswers) {
      setAnswers(savedAnswers);
    }
  }, []);

  // 使用useCallback缓存handleAnswerChange函数，避免子组件不必要的重新渲染
  const handleAnswerChange = useCallback(
    (questionId, answer) => {
      setAnswers(prevAnswers => {
        const newAnswers = { ...prevAnswers, [questionId]: answer };
        return newAnswers;
      });
      logOperation({
        targetElement: `P21_LikertScale_${questionId}`,
        eventType: 'change',
        value: answer,
      });

      // 实时收集答案到answerList，确保即使用户没有点击下一页按钮也能提交答案
      const questionIndex = CURIOSITY_QUESTIONS.findIndex(q => q.id === questionId);
      if (questionIndex !== -1) {
        collectAnswer({
          code: questionIndex + 1,
          targetElement: `P21_好奇心问题${questionIndex + 1}`,
          value: answer,
        });
      }
    },
    [logOperation, collectAnswer]
  );

  // 使用useEffect来保存答案，避免在渲染期间调用setState
  // 使用ref来缓存上一次的answers，避免不必要的保存操作
  const prevAnswersRef = useRef({});
  useEffect(() => {
    if (
      Object.keys(answers).length > 0 &&
      JSON.stringify(answers) !== JSON.stringify(prevAnswersRef.current)
    ) {
      prevAnswersRef.current = answers;
      saveQuestionnaireAnswer(PAGE_ID, answers);
    }
  }, [answers]);

  // 使用useMemo缓存计算结果，避免不必要的重新计算
  const allQuestionsAnswered = useMemo(() => {
    return CURIOSITY_QUESTIONS.every(q => !!answers[q.id]);
  }, [answers]);

  // 缓存disabled状态，避免每次渲染都重新计算
  const isDisabled = useMemo(() => {
    return isSubmitting || isQuestionnaireTimeUp;
  }, [isSubmitting, isQuestionnaireTimeUp]);

  const handleNextPage = async () => {
    if (!allQuestionsAnswered && !isQuestionnaireTimeUp) {
      alert('请回答所有问题后再继续。');
      logOperation({
        targetElement: 'P21_NextButton',
        eventType: 'click_blocked',
        value: 'incomplete',
      });
      return;
    }
    setIsSubmitting(true);
    logOperation({ targetElement: 'P21_NextButton', eventType: 'click' });

    // 同步收集所有答案，避免异步状态更新问题
    const answerList = CURIOSITY_QUESTIONS.map((question, index) => ({
      code: index + 1,
      targetElement: `P21_好奇心问题${index + 1}`,
      value: answers[question.id] || '未回答',
    }));

    // 手动将答案添加到AppContext，确保立即可用
    answerList.forEach(answer => {
      collectAnswer({
        targetElement: answer.targetElement,
        value: answer.value,
        code: answer.code,
      });
    });

    // 等待一个React渲染周期，确保状态更新完成
    await new Promise(resolve => setTimeout(resolve, 0));

    try {
      const success = await submitPageData();
      if (success) {
        await navigateToPage('Page_22_Creativity_Questions', { skipSubmit: true });
      } else {
        alert('数据提交失败，请重试');
      }
    } catch (error) {
      console.error('提交P21数据失败:', error);
      alert('提交答案失败，请稍后重试！');
    } finally {
      setIsSubmitting(false);
    }
  };

  // 使用ref来缓存超时处理，避免无限重新渲染
  const timeoutHandledRef = React.useRef(false);

  useEffect(() => {
    if (isQuestionnaireTimeUp && !isSubmitting && !timeoutHandledRef.current) {
      timeoutHandledRef.current = true;
      setIsSubmitting(true);
      logOperation({
        targetElement: 'P21_System',
        eventType: 'auto_submit',
        value: 'questionnaire_time_up',
      });

      // 同步收集超时时的答案
      const answerList = CURIOSITY_QUESTIONS.map((question, index) => ({
        code: index + 1,
        targetElement: `P21_好奇心问题${index + 1}`,
        value: answers[question.id] || '超时未回答',
      }));

      // 手动将答案添加到AppContext
      answerList.forEach(answer => {
        collectAnswer({
          targetElement: answer.targetElement,
          value: answer.value,
          code: answer.code,
        });
      });

      // 等待状态更新后提交
      setTimeout(() => {
        submitPageData()
          .then(() => {
            navigateToPage('Page_22_Creativity_Questions', { skipSubmit: true });
          })
          .catch(error => {
            console.error('超时自动提交P21数据失败:', error);
          })
          .finally(() => {
            setIsSubmitting(false);
          });
      }, 0);
    }
  }, [isQuestionnaireTimeUp, isSubmitting]);

  return (
    <div className={styles.pageContainer}>
      <div className={styles.questionnaireContent}>
        <p className={styles.pageDescription}>请根据你对下列说法的同意程度进行选择。</p>

        <div className={styles.tableContainer}>
          <LikertScale
            questions={CURIOSITY_QUESTIONS}
            options={LIKERT_OPTIONS_4}
            answers={answers}
            onAnswerChange={handleAnswerChange}
            disabled={isDisabled}
            tableMode={true}
          />
        </div>

        <div className={styles.buttonContainer}>
          <button
            className={styles.nextButton}
            onClick={handleNextPage}
            disabled={(!allQuestionsAnswered && !isQuestionnaireTimeUp) || isSubmitting}
          >
            {isSubmitting ? '提交中...' : '下一页'}
          </button>
          {isQuestionnaireTimeUp && (
            <p className={styles.timeUpMessage}>问卷时间已到，将自动提交您的答案。</p>
          )}
        </div>
      </div>
    </div>
  );
}

