  SET_EXPERIMENT_STATE: 'SET_EXPERIMENT_STATE',
  TICK_NOTICE_COUNTDOWN: 'TICK_NOTICE_COUNTDOWN',
  CONFIRM_NOTICE: 'CONFIRM_NOTICE',
  LOG_OPERATION: 'LOG_OPERATION',
