const createInitialState = (initialPageId) => ({
  currentPageId: initialPageId || 'page_00_notice',
  answers: {
    Q1_控制变量原因: null,
    Q2_抑制作用浓度: null,
    Q3_发芽率趋势: null,
    Q4a_菟丝子有效性: null,
    Q4b_结论理由: null,
  },
  experimentState: {
    ...DEFAULT_EXPERIMENT_STATE,
  },
