const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

function getUserInput() {
  return new Promise((resolve) => {
    rl.question('prompt: ', (answer) => {
      resolve(answer.trim());
    });
  });
}

async function main() {
  console.log('交互式任务循环已启动。输入 "stop" 退出。');
  
  while (true) {
